import React from 'react';
import { useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';

const Cart = () => {
  const navigate = useNavigate();
  const { user } = useAuth();
  const { cart, loading, removeFromCart, updateCartItem, clearCart } = useCart();

  const handleQuantityChange = (productId, newQuantity) => {
    if (newQuantity > 0) {
      updateCartItem(productId, newQuantity);
    }
  };

  const handleRemoveItem = (productId) => {
    removeFromCart(productId);
  };

  const handleCheckout = () => {
    if (!user) {
      alert('Please login to proceed');
      navigate('/auth');
      return;
    }
    navigate('/checkout');
  };

  if (loading) {
    return <div>Loading cart...</div>;
  }

  if (!cart.items || cart.items.length === 0) {
    return <div className="empty-cart">Your cart is empty</div>;
  }

  return (
    <div className="cart-container">
      <h2>Shopping Cart</h2>
      <div className="cart-items">
        {cart.items.map(item => (
          <div key={item.productId?._id || item.productId} className="cart-item">
            <div className="item-info">
              <h4>{item.productId?.name || 'Product'}</h4>
              <p>Price: ₹{item.price}</p>
            </div>
            <div className="item-quantity">
              <button onClick={() => handleQuantityChange(item.productId, item.quantity - 1)}>-</button>
              <input
                type="number"
                value={item.quantity}
                onChange={(e) => handleQuantityChange(item.productId, parseInt(e.target.value))}
              />
              <button onClick={() => handleQuantityChange(item.productId, item.quantity + 1)}>+</button>
            </div>
            <div className="item-total">
              ₹{item.price * item.quantity}
            </div>
            <button onClick={() => handleRemoveItem(item.productId)} className="remove-btn">Remove</button>
          </div>
        ))}
      </div>
      <div className="cart-summary">
        <h3>Total: ₹{cart.totalPrice}</h3>
        <button onClick={handleCheckout} className="checkout-btn">Proceed to Checkout</button>
        <button onClick={clearCart} className="clear-btn">Clear Cart</button>
      </div>
    </div>
  );
};

export default Cart;
